import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState("");

  const navigate = useNavigate();

  useEffect(() => {
    obtenerCategorias();
    obtenerProductos();
  }, []);

  const obtenerCategorias = async () => {
    const res = await axios.get("http://localhost:5000/api/categorias");
    setCategorias(res.data);
  };

  const obtenerProductos = async () => {
    const res = await axios.get("http://localhost:5000/api/productos");
    setProductos(res.data);
  };

  // 🔹 Filtro seguro
  const categoriasFiltradas = categorias.filter((c) =>
    (c.Nombre || "").toLowerCase().includes(busqueda.toLowerCase())
  );

  return (
    <div className="container mt-5">
      <h2 className="mb-4">📦 Categorías</h2>

      {/* Buscador */}
      <input
        type="text"
        className="form-control mb-4"
        placeholder="Buscar categoría..."
        value={busqueda}
        onChange={(e) => setBusqueda(e.target.value)}
      />

      <div className="row g-4">
        {categoriasFiltradas.map((cat) => {
          const productosCategoria = productos.filter(
            (p) => p.CategoriaID === cat.CategoriaID
          );

          return (
            <div key={cat.CategoriaID} className="col-md-4">
              <div
                className="card h-100 shadow-sm"
                style={{ cursor: "pointer" }}
                onClick={() =>
                  navigate(`/productos?categoria=${cat.CategoriaID}`)
                }
              >
                <div className="card-body text-center">
                  <h5 className="card-title fw-bold">
                    {cat.Nombre}
                  </h5>

                  <p className="text-muted">
                    {productosCategoria.length} producto(s)
                  </p>

                  {productosCategoria.length > 0 && (
                    <img
                      src={`http://localhost:5000/uploads/${productosCategoria[0].Imagen}`}
                      alt="preview"
                      className="img-fluid rounded"
                      style={{
                        height: "150px",
                        objectFit: "cover",
                      }}
                    />
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {categoriasFiltradas.length === 0 && (
        <p className="text-center text-muted mt-4">
          No hay categorías disponibles
        </p>
      )}
    </div>
  );
}
